import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a maximum buffer size to prevent buffer overflow
        int maxSize = 10;

        // Ensure that the user input does not exceed the buffer size
        if(userInput.length() > maxSize) {
            System.out.println("Input exceeds maximum buffer size.");
            return;
        }

        char[] buffer = new char[maxSize];

        userInput.getChars(0, Math.min(userInput.length(), maxSize), buffer, 0); // Copy user input into buffer

        System.out.println("Buffer contents: " + new String(buffer)); // Print out buffer contents
    }
}

